/**
 * French Payslip (Bulletin de Paie) Calculator - 2025
 * Calculates all employee and employer cotisations according to French law
 * Stores detailed breakdown in commentaire field as JSON
 */

const raw = $input.first().json;
const body = raw.body || raw;
const data = body.data || body;
const tenantId = String(body.tenantId || data.tenantId || '');

// Validate tenantId format
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRegex.test(tenantId)) {
  throw new Error('Invalid tenantId format');
}

// Helper function: round to 2 decimals
const round2 = (val) => Math.round(val * 100) / 100;

// Helper function: escape SQL single quotes
const esc = (v) => (v == null ? '' : String(v).replace(/'/g, "''"));

// Extract input data
const memberId = data.memberId || '';
const mois = parseInt(data.mois) || new Date().getMonth() + 1;
const annee = parseInt(data.annee) || new Date().getFullYear();
const salaireBase = round2(parseFloat(data.salaireBase) || 0);
const primes = round2(parseFloat(data.primes) || 0);
const heuresSupp25 = round2(parseFloat(data.heuresSupp25) || 0);
const heuresSupp50 = round2(parseFloat(data.heuresSupp50) || 0);
const isCadre = data.isCadre === true;
const tauxImposition = round2(parseFloat(data.tauxImposition) || 0);

// 2025 PMSS (Plafond de la Sécurité Sociale Mensuel)
const PMSS_2025 = 3925;

// Calculate gross salary (brut)
const brutTotal = round2(salaireBase + primes + heuresSupp25 + heuresSupp50);

// ============================================================================
// EMPLOYEE COTISATIONS (Cotisations Salariales)
// ============================================================================

const salariales = {};

// Vieillesse plafonnée (capped at PMSS)
const vieillessePlafonneeBase = Math.min(brutTotal, PMSS_2025);
salariales.vieillessePlafonnee = {
  base: round2(vieillessePlafonneeBase),
  taux: 6.90,
  montant: round2(vieillessePlafonneeBase * 0.069)
};

// Vieillesse déplafonnée (uncapped, on full salary)
salariales.vieillesseDepalonnee = {
  base: round2(brutTotal),
  taux: 0.40,
  montant: round2(brutTotal * 0.004)
};

// AGIRC-ARRCO Tranche 1 (capped at PMSS)
const agirc1Base = Math.min(brutTotal, PMSS_2025);
salariales.agircArrcoT1 = {
  base: round2(agirc1Base),
  taux: 3.15,
  montant: round2(agirc1Base * 0.0315)
};

// AGIRC-ARRCO Tranche 2 (PMSS to 8×PMSS)
const agirc2Min = PMSS_2025;
const agirc2Max = 8 * PMSS_2025;
const agirc2Base = Math.max(0, Math.min(brutTotal, agirc2Max) - agirc2Min);
salariales.agircArrcoT2 = {
  base: round2(agirc2Base),
  taux: 8.64,
  montant: round2(agirc2Base * 0.0864)
};

// CSG and CRDS (applied on 98.25% of gross due to 1.75% exemption)
const csgCrdsBase = round2(brutTotal * 0.9825);
const csgDeductible = {
  base: round2(csgCrdsBase),
  taux: 6.80,
  montant: round2(csgCrdsBase * 0.068)
};
const csgNonDeductible = {
  base: round2(csgCrdsBase),
  taux: 2.40,
  montant: round2(csgCrdsBase * 0.024)
};
const crds = {
  base: round2(csgCrdsBase),
  taux: 0.50,
  montant: round2(csgCrdsBase * 0.005)
};

salariales.csg = {
  deductible: csgDeductible,
  nonDeductible: csgNonDeductible,
  crds: crds
};

// APEC for cadres only (capped at 4×PMSS)
if (isCadre) {
  const apecBase = Math.min(brutTotal, 4 * PMSS_2025);
  salariales.apec = {
    base: round2(apecBase),
    taux: 0.024,
    montant: round2(apecBase * 0.00024)
  };
}

// Total employee cotisations (excluding non-deductible CSG for net calculation)
const totalChargesSalariales = round2(
  salariales.vieillessePlafonnee.montant +
  salariales.vieillesseDepalonnee.montant +
  salariales.agircArrcoT1.montant +
  salariales.agircArrcoT2.montant +
  csgDeductible.montant +
  csgNonDeductible.montant +
  crds.montant +
  (isCadre ? salariales.apec.montant : 0)
);

// ============================================================================
// EMPLOYER COTISATIONS (Cotisations Patronales)
// ============================================================================

const patronales = {};

// Assurance maladie: 7.00% or 13.00% depending on salary level
const assuranceMaladieRate = brutTotal <= 2.5 * PMSS_2025 ? 0.07 : 0.13;
patronales.assuranceMaladie = {
  base: round2(brutTotal),
  taux: assuranceMaladieRate * 100,
  montant: round2(brutTotal * assuranceMaladieRate)
};

// Vieillesse plafonnée (capped at PMSS)
const vieillesse2Base = Math.min(brutTotal, PMSS_2025);
patronales.vieillesse = {
  base: round2(vieillesse2Base),
  taux: 8.55,
  montant: round2(vieillesse2Base * 0.0855)
};

// Vieillesse déplafonnée (uncapped)
patronales.vieillesseDepalonnee = {
  base: round2(brutTotal),
  taux: 2.02,
  montant: round2(brutTotal * 0.0202)
};

// Allocations familiales: 3.45% or 5.25%
const allocFamillesRate = brutTotal <= 3.5 * PMSS_2025 ? 0.0345 : 0.0525;
patronales.allocationsFamiliales = {
  base: round2(brutTotal),
  taux: allocFamillesRate * 100,
  montant: round2(brutTotal * allocFamillesRate)
};

// AGIRC-ARRCO Tranche 1
const agirc1PatBase = Math.min(brutTotal, PMSS_2025);
patronales.agircArrcoT1 = {
  base: round2(agirc1PatBase),
  taux: 4.72,
  montant: round2(agirc1PatBase * 0.0472)
};

// AGIRC-ARRCO Tranche 2
const agirc2PatBase = Math.max(0, Math.min(brutTotal, 8 * PMSS_2025) - PMSS_2025);
patronales.agircArrcoT2 = {
  base: round2(agirc2PatBase),
  taux: 12.95,
  montant: round2(agirc2PatBase * 0.1295)
};

// Assurance chômage
patronales.assuranceChomage = {
  base: round2(brutTotal),
  taux: 4.05,
  montant: round2(brutTotal * 0.0405)
};

// AGS (Garantie des salaires)
patronales.ags = {
  base: round2(brutTotal),
  taux: 0.20,
  montant: round2(brutTotal * 0.002)
};

// FNAL (Fonds National d'Aide au Logement) - 0.10% up to PMSS
const fnalBase = Math.min(brutTotal, PMSS_2025);
patronales.fnal = {
  base: round2(fnalBase),
  taux: 0.10,
  montant: round2(fnalBase * 0.001)
};

// Formation professionnelle continue
patronales.formation = {
  base: round2(brutTotal),
  taux: 0.55,
  montant: round2(brutTotal * 0.0055)
};

// Taxe d'apprentissage
patronales.apprentissage = {
  base: round2(brutTotal),
  taux: 0.68,
  montant: round2(brutTotal * 0.0068)
};

// Contribution Solidarité Autonomie (CSA)
patronales.csa = {
  base: round2(brutTotal),
  taux: 0.30,
  montant: round2(brutTotal * 0.003)
};

// Accidents du Travail / Maladies Professionnelles (average rate)
patronales.atmp = {
  base: round2(brutTotal),
  taux: 1.28,
  montant: round2(brutTotal * 0.0128)
};

// APEC for cadres
if (isCadre) {
  const apecPatBase = Math.min(brutTotal, 4 * PMSS_2025);
  patronales.apec = {
    base: round2(apecPatBase),
    taux: 0.036,
    montant: round2(apecPatBase * 0.00036)
  };
}

// Prévoyance cadre obligatoire (for cadres)
if (isCadre) {
  patronales.prevoyance = {
    base: round2(brutTotal),
    taux: 1.50,
    montant: round2(brutTotal * 0.015)
  };
}

// Calculate total employer cotisations
let totalChargesPatronales = round2(
  patronales.assuranceMaladie.montant +
  patronales.vieillesse.montant +
  patronales.vieillesseDepalonnee.montant +
  patronales.allocationsFamiliales.montant +
  patronales.agircArrcoT1.montant +
  patronales.agircArrcoT2.montant +
  patronales.assuranceChomage.montant +
  patronales.ags.montant +
  patronales.fnal.montant +
  patronales.formation.montant +
  patronales.apprentissage.montant +
  patronales.csa.montant +
  patronales.atmp.montant
);

if (isCadre) {
  totalChargesPatronales = round2(totalChargesPatronales + patronales.apec.montant + patronales.prevoyance.montant);
}

// ============================================================================
// NET SALARY CALCULATION
// ============================================================================

// Net before tax = gross - employee cotisations
const netAvantImpot = round2(brutTotal - totalChargesSalariales);

// Net taxable income = net before tax + non-deductible CSG + CRDS
// (they are non-deductible, so added back to taxable base)
const netImposable = round2(
  netAvantImpot + csgNonDeductible.montant + crds.montant
);

// Income tax withholding (prélèvement à la source)
const montantImpotRevenu = round2(netImposable * tauxImposition);

// Net to pay = net before tax - income tax
const netAPayer = round2(netAvantImpot - montantImpotRevenu);

// ============================================================================
// PREPARE DATABASE INSERT
// ============================================================================

const id = require('crypto').randomUUID();
const now = new Date().toISOString();

// Build detailed cotisations JSON for commentaire field
const detailCotisations = {
  detailCotisations: {
    salariales: salariales,
    patronales: patronales,
    csgCrds: {
      deductible: csgDeductible,
      nonDeductible: csgNonDeductible,
      crds: crds
    }
  },
  brutTotal: brutTotal,
  totalChargesSalariales: totalChargesSalariales,
  totalChargesPatronales: totalChargesPatronales,
  netAvantImpot: netAvantImpot,
  netImposable: netImposable,
  impotRevenu: {
    taux: tauxImposition * 100,
    montant: montantImpotRevenu
  },
  netAPayer: netAPayer,
  pmss: PMSS_2025,
  isCadre: isCadre,
  mois: mois,
  annee: annee
};

const commentaireJSON = esc(JSON.stringify(detailCotisations));

const query = `INSERT INTO rh_bulletins_paie (id, tenant_id, member_id, mois, annee, salaire_base, primes, deductions, charges_patronales, charges_salariales, net_a_payer, net_imposable, statut, commentaire, created_at, updated_at) VALUES ('${esc(id)}', '${esc(tenantId)}', '${esc(memberId)}', ${mois}, ${annee}, ${salaireBase}, ${primes}, 0, ${totalChargesPatronales}, ${totalChargesSalariales}, ${netAPayer}, ${netImposable}, 'valide', '${commentaireJSON}', '${esc(now)}', '${esc(now)}') RETURNING *;`;

return [{json: {query: query, calculatedData: detailCotisations}}];

/**
 * Format response: Parse commentaire JSON and return clean response
 */

const row = $input.first().json;

if (!row || !row.id) {
  return [{json: {
    success: false,
    error: 'Creation failed: No record returned from database',
    timestamp: new Date().toISOString()
  }}];
}

// Parse commentaire JSON if it exists
let commentaireData = null;
try {
  if (row.commentaire) {
    commentaireData = JSON.parse(row.commentaire);
  }
} catch (e) {
  // If JSON parsing fails, store the raw string
  commentaireData = row.commentaire;
}

return [{
  json: {
    success: true,
    data: {
      id: row.id,
      tenantId: row.tenant_id,
      memberId: row.member_id,
      mois: Number(row.mois || 0),
      annee: Number(row.annee || 0),
      // Main salary figures
      salaireBase: Number(row.salaire_base || 0),
      primes: Number(row.primes || 0),
      brutTotal: commentaireData?.brutTotal || 0,
      chargesSalariales: Number(row.charges_salariales || 0),
      chargesPatronales: Number(row.charges_patronales || 0),
      netAvantImpot: commentaireData?.netAvantImpot || 0,
      netImposable: Number(row.net_imposable || 0),
      impotRevenu: commentaireData?.impotRevenu || { taux: 0, montant: 0 },
      netAPayer: Number(row.net_a_payer || 0),
      // Status and detailed data
      statut: row.statut || 'valide',
      isCadre: commentaireData?.isCadre || false,
      // Full cotisations breakdown (for frontend display)
      detailCotisations: commentaireData?.detailCotisations || {},
      // Timestamps
      createdAt: row.created_at,
      updatedAt: row.updated_at
    },
    timestamp: new Date().toISOString()
  }
}];
